def detect_cycle_undirected(graph):
    visited = set()

    for node in graph:
        if node not in visited:
            if _dfs_cycle_check(node, None, visited, graph):
                return True
    return False

def _dfs_cycle_check(current_node, parent_node, visited, graph):
    visited.add(current_node)

    for neighbor in graph.get(current_node, []):
        if neighbor == parent_node:
            continue

        if neighbor in visited:
            return True

        if _dfs_cycle_check(neighbor, current_node, visited, graph):
            return True

    return False
